export function drawTiledDirectedSpriteAlongLocalY(
  ctx: CanvasRenderingContext2D,
  sprite: ImageBitmap,
  x: number,
  y: number,
  width: number,
  height: number,
  direction: Direction,
  tileWidth: number,
  tileHeight: number,
  tileCount: number,
